```

**Complete Handler Flow:**

```go
func (s *Server) DeleteHandler(c *gin.Context) {
    var r api.DeleteRequest

    // Step 1: Parse & validate JSON request body
    if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
        return
    } else if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // Step 2: Parse & normalize model reference
    modelRef, err := parseNormalizePullModelRef(cmp.Or(r.Model, r.Name))
    if err != nil {
        switch {
        case errors.Is(err, errConflictingModelSource):
            c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        case errors.Is(err, model.ErrUnqualifiedName):
            c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("name %q is invalid", cmp.Or(r.Model, r.Name))})
        default:
            c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        }
        return
    }

    // Step 3: Resolve to existing model name (case-insensitive matching)
    n, err := getExistingName(modelRef.Name)
    if err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
        return
    }

    // Step 4: Parse manifest file for the model
    m, err := manifest.ParseNamedManifest(n)
    if err != nil {
        switch {
        case os.IsNotExist(err):
            c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model '%s' not found", cmp.Or(r.Model, r.Name))})
        default:
            c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        }
        return
    }

    // Step 5: Remove manifest file
    if err := m.Remove(); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }

    // Step 6: Remove layers (blobs) that are no longer used by any other manifest
    if err := m.RemoveLayers(); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }
}
```

**Error Handling:**
- **400 Bad Request:** Missing/invalid JSON body, invalid model name, conflicting source suffix
- **404 Not Found:** Model doesn't exist (returns `http.StatusNotFound`)
- **500 Internal Server Error:** Manifest parsing failures, removal failures

**Status Code Summary:**
- `http.StatusBadRequest` (400): Parse/validation errors
- `http.StatusNotFound` (404): Model not found
- `http.StatusInternalServerError` (500): Operational errors

---

### **4. COPY HANDLER**

**File:** `/absolute/path/server/routes.go` (lines 1446-1483)

**Function Signature:**
