```

**Complete Handler Flow:**

```go
func (s *Server) CopyHandler(c *gin.Context) {
    var r api.CopyRequest

    // Step 1: Parse request body
    if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
        return
    } else if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // Step 2: Validate source model name
    src := model.ParseName(r.Source)
    if !src.IsValid() {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("source %q is invalid", r.Source)})
        return
    }

    // Step 3: Resolve source to existing model (case-insensitive)
    src, err := getExistingName(src)
    if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // Step 4: Validate destination model name
    dst := model.ParseName(r.Destination)
    if !dst.IsValid() {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("destination %q is invalid", r.Destination)})
        return
    }

    // Step 5: Resolve destination to existing model
    dst, err = getExistingName(dst)
    if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // Step 6: Perform the copy operation
    if err := CopyModel(src, dst); errors.Is(err, os.ErrNotExist) {
        c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model %q not found", r.Source)})
    } else if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
    }
    // Note: No success response body; just returns status 200
}
```

**Error Handling:**
- **400 Bad Request:** Missing/invalid JSON, invalid source/destination names
- **404 Not Found:** Source model doesn't exist (`os.ErrNotExist`)
- **500 Internal Server Error:** Copy operation failures
- **Note:** No 409 Conflict handling for destination already existing (allows overwrite)

**Status Code Summary:**
- `http.StatusBadRequest` (400): Parse/validation errors
- `http.StatusNotFound` (404): Source model not found
- `http.StatusInternalServerError` (500): Copy operation failures

---

### **5. API REQUEST/RESPONSE TYPES**

